import{_ as a,o as i,c as l,ag as r}from"./chunks/framework.DAvaMl8U.js";const p=JSON.parse('{"title":"Feature Ideas: Search, Semantic Retrieval, and RAG","description":"","frontmatter":{},"headers":[],"relativePath":"feature-ideas.md","filePath":"feature-ideas.md"}'),t={name:"feature-ideas.md"};function n(o,e,s,d,c,u){return i(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="feature-ideas-search-semantic-retrieval-and-rag" tabindex="-1">Feature Ideas: Search, Semantic Retrieval, and RAG <a class="header-anchor" href="#feature-ideas-search-semantic-retrieval-and-rag" aria-label="Permalink to &quot;Feature Ideas: Search, Semantic Retrieval, and RAG&quot;">​</a></h1><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Current search behavior is hybrid rerank:</p><ol><li>Lexical retrieval runs first (FTS, then fuzzy fallback).</li><li>Semantic embeddings rerank lexical candidates.</li><li>If lexical retrieval returns zero rows, semantic retrieval does not currently run independently.</li></ol><p>This means semantic search is active, but not yet used as a standalone retrieval channel.</p><hr><h2 id="problem-statement" tabindex="-1">Problem Statement <a class="header-anchor" href="#problem-statement" aria-label="Permalink to &quot;Problem Statement&quot;">​</a></h2><p>Some documents are indexed and embedded but still hard to retrieve when the query has weak lexical overlap.</p><p>Example pattern:</p><ul><li>Query terms and document wording differ strongly.</li><li>Lexical stage returns zero rows.</li><li>Rerank stage never executes because there are no candidates to rerank.</li></ul><hr><h2 id="proposed-features" tabindex="-1">Proposed Features <a class="header-anchor" href="#proposed-features" aria-label="Permalink to &quot;Proposed Features&quot;">​</a></h2><h2 id="_1-semantic-only-fallback-high-priority" tabindex="-1">1. Semantic-Only Fallback (High Priority) <a class="header-anchor" href="#_1-semantic-only-fallback-high-priority" aria-label="Permalink to &quot;1. Semantic-Only Fallback (High Priority)&quot;">​</a></h2><p>When lexical retrieval returns zero or very weak results:</p><ol><li>Embed the query.</li><li>Compute similarity against chunk embeddings.</li><li>Return top-k matched chunks/documents.</li><li>Optionally blend with any weak lexical results.</li></ol><p>Expected impact:</p><ul><li>Better recall for paraphrased, intent-based, and conceptual queries.</li><li>Direct fix for &quot;indexed but not found&quot; cases.</li></ul><p>Notes:</p><ul><li>Use existing <code>document_chunks.embedding</code> field.</li><li>Add a SQL path that selects by similarity and groups best chunk per document.</li></ul><hr><h2 id="_2-hybrid-dual-channel-retrieval-known-pattern" tabindex="-1">2. Hybrid Dual-Channel Retrieval (Known Pattern) <a class="header-anchor" href="#_2-hybrid-dual-channel-retrieval-known-pattern" aria-label="Permalink to &quot;2. Hybrid Dual-Channel Retrieval (Known Pattern)&quot;">​</a></h2><p>Run lexical and semantic retrieval in parallel, then fuse rankings.</p><p>Suggested approach:</p><ol><li>Lexical channel: current FTS/fuzzy results.</li><li>Semantic channel: top-k vector similarity results.</li><li>Fusion: Reciprocal Rank Fusion (RRF) or weighted rank blending.</li><li>Final rerank: optional lightweight rerank over merged top N.</li></ol><p>Expected impact:</p><ul><li>Exact token matches still win where appropriate.</li><li>Semantic matches rescue paraphrase and intent mismatches.</li><li>Better overall precision-recall balance.</li></ul><hr><h2 id="_3-search-mode-controls-product-ux" tabindex="-1">3. Search Mode Controls (Product UX) <a class="header-anchor" href="#_3-search-mode-controls-product-ux" aria-label="Permalink to &quot;3. Search Mode Controls (Product UX)&quot;">​</a></h2><p>Add explicit search modes without breaking default UX.</p><p>Proposed API parameter:</p><ul><li><code>search_mode=lexical|semantic|hybrid</code></li></ul><p>Behavior:</p><ul><li><code>lexical</code>: current FTS/fuzzy only.</li><li><code>semantic</code>: vector retrieval only.</li><li><code>hybrid</code>: both channels + fusion (default).</li></ul><p>Benefits:</p><ul><li>Easier debugging and relevance tuning.</li><li>Power users can choose mode by task.</li></ul><hr><h2 id="_4-rag-feature-retrieval-augmented-generation" tabindex="-1">4. RAG Feature (Retrieval-Augmented Generation) <a class="header-anchor" href="#_4-rag-feature-retrieval-augmented-generation" aria-label="Permalink to &quot;4. RAG Feature (Retrieval-Augmented Generation)&quot;">​</a></h2><p>RAG is not the same as semantic search.</p><ul><li>Semantic search: retrieve/rank relevant documents by meaning.</li><li>RAG: retrieve context first, then generate an answer with an LLM.</li></ul><p>Proposed RAG pipeline:</p><ol><li>User asks a natural-language question.</li><li>Retrieve top chunks (hybrid retrieval preferred).</li><li>Build prompt with citations/snippets.</li><li>Generate answer with LLM.</li><li>Return answer + cited sources + confidence metadata.</li></ol><p>Minimum viable RAG endpoint:</p><ul><li><code>POST /orgs/:orgSlug/ask</code></li><li>Input: <code>{ question: string, connector_id?: string, top_k?: number }</code></li><li>Output: <code>{ answer, citations, used_chunks, model, latency_ms }</code></li></ul><p>Safety and quality requirements:</p><ul><li>Require citations for each major claim.</li><li>Decline confidently when retrieval confidence is low.</li><li>Log retrieval evidence for traceability.</li></ul><hr><h2 id="_5-embedding-backfill-and-ops" tabindex="-1">5. Embedding Backfill and Ops <a class="header-anchor" href="#_5-embedding-backfill-and-ops" aria-label="Permalink to &quot;5. Embedding Backfill and Ops&quot;">​</a></h2><p>Current manual backfill is available via:</p><ul><li><code>POST /connectors/:connectorId/embed?org=:orgSlug</code></li><li><code>POST /documents/:documentId/embed?org=:orgSlug</code></li><li><code>POST /orgs/:orgSlug/embed</code></li></ul><p>Enhancements to consider:</p><ol><li>Add progress metrics in UI (embedded chunks, skipped chunks, failures).</li><li>Add background embed queue for long-running org-wide backfills.</li><li>Add embed versioning to force controlled re-embedding when model changes.</li></ol><hr><h2 id="implementation-plan-phased" tabindex="-1">Implementation Plan (Phased) <a class="header-anchor" href="#implementation-plan-phased" aria-label="Permalink to &quot;Implementation Plan (Phased)&quot;">​</a></h2><h2 id="phase-1" tabindex="-1">Phase 1 <a class="header-anchor" href="#phase-1" aria-label="Permalink to &quot;Phase 1&quot;">​</a></h2><ol><li>Add semantic-only fallback when lexical returns zero.</li><li>Add search response metadata: retrieval path (<code>lexical</code>, <code>semantic_fallback</code>, <code>hybrid</code>).</li><li>Add basic tests with paraphrase queries.</li></ol><h2 id="phase-2" tabindex="-1">Phase 2 <a class="header-anchor" href="#phase-2" aria-label="Permalink to &quot;Phase 2&quot;">​</a></h2><ol><li>Add dual-channel retrieval with RRF fusion.</li><li>Add <code>search_mode</code> query param.</li><li>Add relevance telemetry (hit counts per channel).</li></ol><h2 id="phase-3" tabindex="-1">Phase 3 <a class="header-anchor" href="#phase-3" aria-label="Permalink to &quot;Phase 3&quot;">​</a></h2><ol><li>Add RAG endpoint with citations.</li><li>Add answer quality guardrails.</li><li>Add observability for retrieval context and token/cost usage.</li></ol><hr><h2 id="success-metrics" tabindex="-1">Success Metrics <a class="header-anchor" href="#success-metrics" aria-label="Permalink to &quot;Success Metrics&quot;">​</a></h2><ol><li>Recall@k improvement for paraphrase queries.</li><li>Fewer zero-result searches on indexed corpora.</li><li>Better top-3 relevance on user-evaluated test sets.</li><li>RAG answer acceptance rate with citation trust.</li></ol><hr><h2 id="open-questions" tabindex="-1">Open Questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open Questions&quot;">​</a></h2><ol><li>Should semantic fallback trigger only on zero lexical results, or also on low lexical confidence?</li><li>Should hybrid fusion be static weights or adaptive by query type?</li><li>Do we migrate to pgvector ANN index for scale, or keep JSON embedding + app-side similarity first?</li><li>What LLM/model policy should be used for RAG generation?</li></ol>',65)])])}const m=a(t,[["render",n]]);export{p as __pageData,m as default};
